var yb = {
    id: function(str) {
        return document.getElementById(str);
    },
};

var tag = "";

yb.id("search").onkeyup = function(e) {
    if (!e.keyCode.toString().match(/^(37|38|39|40|13|16|17|18|224)$/)) {
        if (tag !== "") {
            document.body.removeChild(tag);
        }

        tag = document.createElement("script");
        var term = yb.id("search").value;
        var lang = yb.id("lang").value;
        var site = yb.id("site").value;

        tag.src =
            "https://" + lang + "." + site  + ".org/w/api.php?action=opensearch&limit=10&format=json&callback=ybComplete&search=" +
            term;
        document.body.appendChild(tag);
    }
};

function ybComplete(data) {
    yb.id("wikiOutput").innerHTML = "";
	const lang = yb.id("lang").value;
	const site = yb.id("site").value;
    for (var i = 0; i < 5; i++) {
        if (data[1][i]) {
            yb.id("wikiOutput").innerHTML +=
                '<p><a href="https://' + lang + '.' + site + '.org/wiki/' +
                data[1][i] +
                '">' +
                data[1][i] +
                "</a><span class=" + "remove" + " onclick=" + "removeItem(this)" + ">&#10005;</span><br>" +
                data[2][i] +
				"</p>";
		} else {
			return;
		}

		if (!data[1][i]) {
			yb.id("wikiOutput").style.paddingTop = 0;
			return;
		}
    }
}

function removeItem(item) {
	item.parentNode.remove();
}

const input = document.querySelector("input");
const borderFix = document.getElementById("borderFix");

input.addEventListener("input", (evt) => {
	const value = input.value;
	if (!value) {
    input.dataset.state = "autocompleteOff";

		return;
	} else {
    input.dataset.state = "autocompleteOn";

	}
});

